  ('judicial-d35ec6db-moex-00297', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '依司法院大法官解釋意旨，獨立機關之設置是否合憲，應綜合各項因素判斷能否維持一定之民主正當性基 礎，下列何者非屬之？', '["設置之目的係為追求憲法上之公共利益", "所職司之任務具有特殊性，並有正當理由足以證立設置之必要性", "重要事項以聽證程序決定，任務執行績效應透明、公開，以方便公眾監督", "立法院對於獨立機關重要人員之任命享有完全之決定與制衡權限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00298', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '依憲法增修條文及司法院大法官解釋意旨，關於立法委員，下列敘述何者正確？', '["區域立法委員，應依各直轄市、縣市及鄉鎮市人口比例分配，並按應選名額劃分同額選舉區選出", "全國不分區及僑居國外國民之立法委員，依政黨名單選舉之，各政黨當選名單中婦女不得低於二分之一", "總統於立法院解散後所發布之緊急命令，應由新任立法委員於就職後追認之", "立法委員於院內公聽會之發言，對外不負民事上損害賠償責任或受刑事上之訴追，亦不負任何行政責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
