  ('judicial-d35ec6db-moex-00300', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '關於司法院大法官，下列敘述何者錯誤？', '["大法官任期8年，不分屆次，個別計算，並不得連任", "大法官須超出黨派以外，獨立行使職權，不受任何干涉", "司法院設大法官若干人，並以其中一人為院長、一人為副院長，由總統提名，經立法院同意任命之", "並為院長、副院長之大法官，不受任期之保障"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00301', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '下列何者屬於憲法法庭之職權？', '["統一法令解釋", "總統罷免案之審理", "大法庭裁定", "法官彈劾案之審理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00302', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '依司法院釋字第527號解釋及憲法訴訟法規定，有關地方之組織及權限，下列敘述何者錯誤？', '["地方自治團體依法享有自主組織權及對自治事項制定規章並執行之權限", "地方自治團體及其所屬機關之組織，應由地方立法機關依中央主管機關所擬訂之準則制定組織自治條例 規定", "地方機關未依法規所設置之機關及所置人員，地方立法機關得刪除其相關預算、審計機關得依法剔除、 追繳其支出", "地方自治團體對函告無效之內容持不同意見時，一律由地方自治團體直接向憲法法庭聲請判決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00303', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '關於法律之種類，下列敘述何者錯誤？', '["成文法須經過一定之立法程序，不成文法無制定與公布之程序", "土地法相對於民法為特別法，但相對於耕地三七五減租條例則為普通法", "公法法規為強行法，私法法規為任意法", "民法為典型之實體法，但其中亦有關於程序之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
